-- AutoHire migration 024 — demo fleet: 500 cars across Rwanda, Dubai & China.
--
-- Investor-facing seed data. 440 of the 500 cars are ELECTRIC (85%+ green
-- fleet) — the rest are combustion/hybrid. Cars are spread 200 Rwanda / 150 Dubai / 150 China,
-- across every city + pickup area in each market (with map coordinates), and
-- priced in each market's local currency (RWF / AED / CNY), so the country
-- selector + multi-currency pricing + daily FX all have real data to show.
--
-- Every photo on a listing is BRAND-MATCHED (a Tesla shows 3 Tesla shots, not 3
-- random cars) via loremflickr keywords.
--
-- Requires migration-023 (listings.country + price_currency) and, for pricing to
-- display in other currencies, migration-022 (fx_rates). Safe to re-run: the cars
-- are deleted + reinserted so re-running REFRESHES the photos even on rows you
-- already inserted. Remove for good with:  delete from listings where id like 'demo-car-%';
--
-- Apply in the Supabase SQL editor.

-- Demo host accounts (2 per market: one fleet business, one individual). These
-- are catalogue-only profiles (no auth.users login) — enough to show inventory.
insert into profiles
  (id, full_name, email, phone, role, joined_at, verification, rating_avg, rating_count,
   owner_type, business_name, payout_terms, insurance_type, vehicle_count)
