  ('demo-host-rw-2', 'Jean-Paul Mugisha', 'jp.mugisha@example.com', '+250788200200', 'owner', '2025-02-01', 'verified', 4.8, 120, 'individual', null, 'per_trip', 'platform_provided', 100),
  ('demo-host-ae-1', 'Dubai Prestige Cars', 'rentals@dxbprestige.example', '+971501234567', 'owner', '2025-02-01', 'verified', 4.8, 95, 'business', 'Dubai Prestige Cars', 'net_30', 'commercial', 75),
  ('demo-host-ae-2', 'Ahmed Rahman', 'ahmed.r@example.com', '+971552345678', 'owner', '2025-02-01', 'verified', 4.8, 95, 'individual', null, 'per_trip', 'platform_provided', 75),
  ('demo-host-cn-1', 'Shanghai EV Fleet', 'hello@shevfleet.example', '+8613800138000', 'owner', '2025-02-01', 'verified', 4.8, 95, 'business', 'Shanghai EV Fleet', 'net_30', 'commercial', 75),
